+import { inject, Injectable, signal } from "@angular/core";
+import { BehaviorSubject, shareReplay } from "rxjs";
+import { BaseService } from "shared/services/BaseService";
+import { BaseComponentSettings } from "shared/classes/Settings/BaseComponentSettings";
+import { Common } from "shared/Common";
+import { NomenclatureMasterFormCategories } from "shared/enums/NomenclatureMaster";
+import { ComponentSettingsService } from "shared/services/ComponentSettingsService";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+
+export interface ChecklistTemplatesNomenclature {
+    NoRecords: string;
+    EditRecord: string;
+    EditInNewTab: string;
+    DeleteRecord: string;
+    GroupByHeader: string;
+}
+
+@Injectable()
+export class ChecklistTemplatesService extends BaseService {
+    private readonly _componentSettingsService = inject(ComponentSettingsService);
+
+    private readonly _templatesSubject = new BehaviorSubject<unknown[]>([]);
+    public readonly templates$ = this._templatesSubject.asObservable().pipe(
+        shareReplay(1)
+    );
+
+    private readonly _nomenclature = signal<ChecklistTemplatesNomenclature>({
+        NoRecords: "",
+        EditRecord: "",
+        EditInNewTab: "",
+        DeleteRecord: "",
+        GroupByHeader: "",
+    });
+    public readonly nomenclature = this._nomenclature.asReadonly();
+
+    constructor() {
+        super();
+
+        this.subscribeTo(this._componentSettingsService.settings$, (settings: BaseComponentSettings) => {
+            if (settings) {
+                this.loadNomenclature(settings);
+            }
+        });
+    }
+
+    public refreshData(): void {
+        Promise.all([
+            this.api.ChecklistTemplateSystem.GetTemplatesByState(true),
+            this.api.ChecklistTemplateSystem.GetTemplatesByState(false),
+        ])
+            .then(([published, unpublished]) => {
+                const all = [...(published ?? []), ...(unpublished ?? [])];
+                this._templatesSubject.next(all);
+            })
+            .catch(this.handlePromiseCatch.bind(this));
+    }
+
+    public deleteTemplates(ids: number[]): void {
+        this.api.CoreSystem.DeleteRecords(ids, PrologTableTypes.ChecklistTemplate)
+            .then(() => {
+                this.refreshData();
+            })
+            .catch(this.handlePromiseCatch.bind(this));
+    }
+
+    private loadNomenclature(settings: BaseComponentSettings): void {
+        this._nomenclature.set({
+            NoRecords: Common.getNomenclature(NomenclatureMasterFormCategories.NonFieldLabel, "NoRecords", settings) || "",
+            EditRecord: Common.getNomenclature(NomenclatureMasterFormCategories.NonFieldLabel, "EditRecord", settings) || "",
+            EditInNewTab: Common.getNomenclature(NomenclatureMasterFormCategories.NonFieldLabel, "EditInNewTab", settings) || "",
+            DeleteRecord: Common.getNomenclature(NomenclatureMasterFormCategories.ButtonLabel, "DeleteRecord", settings) || "",
+            GroupByHeader: Common.getNomenclature(NomenclatureMasterFormCategories.NonFieldLabel, "GroupByHeader", settings) || "",
+        });
+    }
+}

